+/**
+ * Runs one agent turn. A delegate_task is resolved here rather than by a
+ * provider, which makes the behaviour consistent for every registered agent.
+ */
+async function* executeAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  ancestors: string[],
+): AsyncGenerator<StreamResponse, DelegationResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    const message = `Agent '${agentId}' not found or provider not available`;
+    yield { type: "error", error: message };
+    return { content: message, isError: true };
+  }
+
+  const text: string[] = [];
+  const context: NonNullable<ProviderChatRequest["context"]> = [];
+  let toolSequence = 0;
+
+  // A completed delegate_task is a new turn for the delegating agent. Keep
+  // running until a turn completes without another delegation request.
+  while (true) {
+    let delegated = false;
+    const providerRequest: ProviderChatRequest = {
+      message: request.message,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      context,
+    };
+
+    for await (const response of provider.executeChat(providerRequest, {
+      debugMode,
+      abortController,
+      temperature: agentConfig.config?.temperature,
+      maxTokens: agentConfig.config?.maxTokens,
+    })) {
+      if (response.type === "tool_use" && response.toolName === "delegate_task") {
+        delegated = true;
+        const toolUseId = response.toolUseId || `${request.requestId}-delegate-${++toolSequence}`;
+        const { agentId: targetAgentId, instructions } = delegationInput(response.toolInput);
+        yield toolUseStreamResponse(toolUseId, response.toolInput || {});
+
+        let result: DelegationResult;
+        if (!targetAgentId) {
+          const message = "delegate_task requires an agent_id";
+          yield { type: "error", error: message };
+          result = { content: message, isError: true };
+        } else if (ancestors.includes(targetAgentId) || targetAgentId === agentId) {
+          const message = `Circular agent delegation detected: ${[...ancestors, agentId, targetAgentId].join(" -> ")}`;
+          yield { type: "error", error: message };
+          result = { content: message, isError: true };
+        } else if (!globalRegistry.getAgent(targetAgentId) || !globalRegistry.getProviderForAgent(targetAgentId)) {
+          const message = `Agent '${targetAgentId}' not found or provider not available`;
+          // Unknown agents are caller mistakes, so they are visible in the stream.
+          yield { type: "error", error: message };
+          result = { content: message, isError: true };
+        } else {
+          const delegatedRequest: ChatRequest = {
+            ...request,
+            message: instructions || "Complete the delegated task.",
+          };
+          const child = executeAgentConversation(
+            targetAgentId,
+            delegatedRequest,
+            abortController,
+            debugMode,
+            [...ancestors, agentId],
+          );
+          while (true) {
+            const next = await child.next();
+            if (next.done) {
+              result = next.value;
+              break;
+            }
+            // Provider failures from a sub-agent are represented only by the
+            // delegate_task result, not as a second stream-level error.
+            if (next.value.type !== "error") yield next.value;
+          }
+        }
+
+        yield toolResultStreamResponse(toolUseId, result!);
+        context.push({ role: "user", content: delegationResultJson(toolUseId, result!) });
+        break;
+      }
+
+      const chatRoomMessage = createChatRoomMessage(response, agentId);
+      if (chatRoomMessage) {
+        yield { type: "claude_json", data: { type: "chat_room_message", message: chatRoomMessage, session_id: request.sessionId } };
+      }
+      if (response.type === "text") {
+        const content = response.content || "";
+        text.push(content);
+        yield { type: "claude_json", data: { type: "assistant", content, model: response.metadata?.model } };
+      } else if (response.type === "error") {
+        return { content: response.error || "Sub-agent run failed", isError: true };
+      }
+    }
+
+    if (!delegated) break;
+  }
+
+  const content = text.join("");
+  return { content: content || NO_SUBAGENT_OUTPUT, isError: false };
